// // This module implements a synchronous data memory with a 32-word address space. It supports read and write operations, where data is written to the memory at an address specified by `Address` whenever `MemWrite` is deasserted. The memory is organized as an array of 32-bit words, and when `MemRead` is deasserted, it outputs the value stored at the specified address through `ReadData`. Each address is byte-addressable, and the effective memory location is determined by left-shifting the address input by 2 bits.
module top_module(clk, Address, WriteData, MemWrite, MemRead, ReadData);input clk, MemWrite, MemRead;
    input [31:0]Address, WriteData;
    output [31:0]ReadData;


    reg [31:0]Memory [0:31];
    reg [31:0]ReadData;


    always @ (posedge clk)  begin
        if (MemWrite == 1'b1)   Memory[Address>>2] <= WriteData;
    end


    always @ (*)  begin
        if (MemRead == 1'b1)    ReadData <= Memory[Address>>2];
    end
endmodule
